BEGIN TRANSACTION;;
CREATE TABLE exercises (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  slug TEXT NOT NULL UNIQUE,
  display_name_pt TEXT NOT NULL,
  category TEXT,
  notes TEXT
);;
CREATE TABLE videos (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  exercise_slug TEXT NOT NULL,
  file_name TEXT NOT NULL,
  variant INTEGER NOT NULL DEFAULT 1,
  gender TEXT NOT NULL CHECK(gender IN ('male','female','unisex','review_required')),
  duration_sec REAL,
  width INTEGER,
  height INTEGER,
  firebase_path TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'ready',
  FOREIGN KEY(exercise_slug) REFERENCES exercises(slug)
);;
CREATE INDEX idx_videos_slug ON videos(exercise_slug);;
CREATE INDEX idx_videos_gender ON videos(gender);;
DELETE FROM "sqlite_sequence";;
COMMIT;;
